mapper.select:
SELECT p.ID, p.PAGE_NAME, p.PAGE_LABEL, p.DISPLAY_MODE, p.PAGE_SORT, p.CREATE_TIME, p.UPDATE_TIME, (SELECT USERNAME FROM user u WHERE u.ID = p.CREATE_USER) AS CREATE_USERNAME, (SELECT USERNAME FROM user u WHERE u.ID = p.UPDATE_USER) AS UPDATE_USERNAME FROM page p
AND p.PAGE_NAME LIKE #{pageNameBind}
AND p.PAGE_LABEL LIKE #{pageLabelBind}
ORDER BY p.PAGE_SORT
